// Harmonic Waves
// Adapted from GenerativeArtGallery / artwork3

p.setup = function() {
  p.createCanvas(400, 400);
  p.colorMode(p.HSB, 360, 100, 100, 100);
  p.frameRate(30);
};

p.draw = function() {
  let wcStr = p.getSynthVar('wave_count') || 'several';
  let ampStr = p.getSynthVar('amplitude') || 'moderate';
  let speedStr = p.getSynthVar('wave_speed') || 'medium';
  let weightStr = p.getSynthVar('line_weight') || 'thin';
  let trailStr = p.getSynthVar('trail_mode') || 'ghostly';
  let colorStr = p.getSynthVar('color_mode') || 'rainbow';

  let waveCount = wcStr === 'few' ? 3 : wcStr === 'several' ? 6 : wcStr === 'many' ? 12 : 20;
  let amp = ampStr === 'subtle' ? 28 : ampStr === 'moderate' ? 60 : 105;
  let speed = speedStr === 'slow' ? 0.012 : speedStr === 'medium' ? 0.03 : 0.07;
  let lw = weightStr === 'hair' ? 0.8 : weightStr === 'thin' ? 2 : 5;
  let bgAlpha = trailStr === 'crisp' ? 100 : trailStr === 'ghostly' ? 14 : 3;

  p.background(0, 0, 5, bgAlpha);

  let t = p.frameCount;

  for (let w = 0; w < waveCount; w++) {
    let frac = w / waveCount;
    let hue;
    if (colorStr === 'rainbow') hue = (frac * 360 + t * 0.4) % 360;
    else if (colorStr === 'cool') hue = 190 + frac * 70;
    else if (colorStr === 'warm') hue = frac * 55;
    else if (colorStr === 'ember') hue = 10 + frac * 35;
    else hue = (frac * 360 + t * 0.4) % 360;

    p.stroke(hue, 80, 92, 85);
    p.strokeWeight(lw);
    p.noFill();

    let freq = 1 + w * 0.6;
    let phase = w * p.TWO_PI / waveCount;
    let baseY = p.height / 2;

    p.beginShape();
    for (let x = 0; x <= p.width; x += 3) {
      let angle = (x / p.width) * p.TWO_PI * freq + t * speed + phase;
      let y = baseY + p.sin(angle) * amp;
      p.vertex(x, y);
    }
    p.endShape();
  }
};
